console.log('Arrow funksiyası nümunəsi...');
const sayHello = () => {
    console.log('Salam, Dünya!');
};
sayHello();
// Output:
// Arrow funksiyası nümunəsi...
// Salam, Dünya!

console.log('Parametrlər və ima edilmiş return nümunəsi...');
const addNumbers = (a, b) => a + b;
const result = addNumbers(5, 3);
console.log('Nəticə:', result);
// Output:
// Parametrlər və ima edilmiş return nümunəsi...
// Nəticə: 8

console.log('Hoisting olmaması nümunəsi...');
// greet(); // Səhv: greet is not a function
const greet = () => console.log('Salam!');
greet();
// Output:
// Hoisting olmaması nümunəsi...
// Salam!

console.log('Funksiya scope-u nümunəsi...');
const showMessage = () => {
    const message = 'Funksiya daxilində';
    console.log(message);
};
showMessage();
// console.log(message); // Səhv: message is not defined
// Output:
// Funksiya scope-u nümunəsi...
// Funksiya daxilində

console.log('this davranışı nümunəsi...');
const person = {
    name: 'Ali',
    sayName: function() {
        const arrowFunc = () => console.log(this.name);
        arrowFunc();
    }
};
person.sayName();
// Output:
// this davranışı nümunəsi...
// Ali

console.log('Arrow funksiyası vs digər funksiyalar nümunəsi...');
// Funksiya elanı
sayHi(); // İşləyir
function sayHi() {
    console.log('Salam (elan)!');
}
// Funksiya ifadəsi
// sayBye(); // Səhv: sayBye is not a function
const sayBye = function() {
    console.log('Salam (ifadə)!');
};
// Arrow funksiyası
// sayArrow(); // Səhv: sayArrow is not a function
const sayArrow = () => console.log('Salam (arrow)!');
sayBye();
sayArrow();
// Output:
// Arrow funksiyası vs digər funksiyalar nümunəsi...
// Salam (elan)!
// Salam (ifadə)!
// Salam (arrow)!

console.log('var, let, const ilə arrow funksiyası nümunəsi...');
const exampleConst = () => console.log('Const ilə');
let exampleLet = () => console.log('Let ilə');
var exampleVar = () => console.log('Var ilə');
exampleConst();
exampleLet();
exampleVar();
// Output:
// var, let, const ilə arrow funksiyası nümunəsi...
// Const ilə
// Let ilə
// Var ilə

console.log('Səhvə yol açan nümunə...');
const calculateArea = (width, height) => {
    const area = width * height;
    // return area; // Unutqan return
};
const result = calculateArea(4, 5);
console.log('Nəticə:', result);
// Output:
// Səhvə yol açan nümunə...
// Nəticə: undefined

