console.log('Arrow function example...');
const sayHello = () => {
    console.log('Hello, World!');
};
sayHello();
// Output:
// Arrow function example...
// Hello, World!

console.log('Parameters and implicit return example...');
const addNumbers = (a, b) => a + b;
const result = addNumbers(5, 3);
console.log('Result:', result);
// Output:
// Parameters and implicit return example...
// Result: 8

console.log('No hoisting example...');
// greet(); // Error: greet is not a function
const greet = () => console.log('Hello!');
greet();
// Output:
// No hoisting example...
// Hello!

console.log('Function scope example...');
const showMessage = () => {
    const message = 'Inside function';
    console.log(message);
};
showMessage();
// console.log(message); // Error: message is not defined
// Output:
// Function scope example...
// Inside function

console.log('this behavior example...');
const person = {
    name: 'Alice',
    sayName: function() {
        const arrowFunc = () => console.log(this.name);
        arrowFunc();
    }
};
person.sayName();
// Output:
// this behavior example...
// Alice

console.log('Arrow function vs other functions example...');
// Function declaration
sayHi(); // Works
function sayHi() {
    console.log('Hello (declaration)!');
}
// Function expression
// sayBye(); // Error: sayBye is not a function
const sayBye = function() {
    console.log('Hello (expression)!');
};
// Arrow function
// sayArrow(); // Error: sayArrow is not a function
const sayArrow = () => console.log('Hello (arrow)!');
sayBye();
sayArrow();
// Output:
// Arrow function vs other functions example...
// Hello (declaration)!
// Hello (expression)!
// Hello (arrow)!

console.log('var, let, const with arrow function example...');
const exampleConst = () => console.log('With const');
let exampleLet = () => console.log('With let');
var exampleVar = () => console.log('With var');
exampleConst();
exampleLet();
exampleVar();
// Output:
// var, let, const with arrow function example...
// With const
// With let
// With var

console.log('Error-prone example...');
const calculateArea = (width, height) => {
    const area = width * height;
    // return area; // Forgotten return
};
const result = calculateArea(4, 5);
console.log('Result:', result);
// Output:
// Error-prone example...
// Result: undefined

