console.log('Пример стрелочной функции...');
const sayHello = () => {
    console.log('Привет, мир!');
};
sayHello();
// Output:
// Пример стрелочной функции...
// Привет, мир!

console.log('Пример параметров и неявного возврата...');
const addNumbers = (a, b) => a + b;
const result = addNumbers(5, 3);
console.log('Результат:', result);
// Output:
// Пример параметров и неявного возврата...
// Результат: 8

console.log('Пример отсутствия поднятия...');
// greet(); // Ошибка: greet is not a function
const greet = () => console.log('Привет!');
greet();
// Output:
// Пример отсутствия поднятия...
// Привет!

console.log('Пример области видимости функции...');
const showMessage = () => {
    const message = 'Внутри функции';
    console.log(message);
};
showMessage();
// console.log(message); // Ошибка: message is not defined
// Output:
// Пример области видимости функции...
// Внутри функции

console.log('Пример поведения this...');
const person = {
    name: 'Алиса',
    sayName: function() {
        const arrowFunc = () => console.log(this.name);
        arrowFunc();
    }
};
person.sayName();
// Output:
// Пример поведения this...
// Алиса

console.log('Пример стрелочной функции против других функций...');
// Объявление функции
sayHi(); // Работает
function sayHi() {
    console.log('Привет (объявление)!');
}
// Функциональное выражение
// sayBye(); // Ошибка: sayBye is not a function
const sayBye = function() {
    console.log('Привет (выражение)!');
};
// Стрелочная функция
// sayArrow(); // Ошибка: sayArrow is not a function
const sayArrow = () => console.log('Привет (стрелочная)!');
sayBye();
sayArrow();
// Output:
// Пример стрелочной функции против других функций...
// Привет (объявление)!
// Привет (выражение)!
// Привет (стрелочная)!

