let exampleLet = () => console.log('С let');
var exampleVar = () => console.log('С var');
exampleConst();
exampleLet();
exampleVar();
// Output:
// Пример var, let, const со стрелочной функцией...
// С const
// С let
// С var

console.log('Пример с ошибкой...');
